variables x ; y = 0 ; b = [i ∈ 1..N ↦→ FALSE] ;
process (Proc ∈ 1..N)
variable j ;
{ ncs: while (TRUE) {
skip ; \∗ The noncritical section.
start: b[self] := TRUE ;
l1: x := self ;
l2: if (y ̸= 0) { l3: b[self] := FALSE ;
