goto start } ;
l5: y := self ;
l6: if (x ̸= self)
{ l7: b[self] := FALSE ;
j := 1 ;
l8: while (j ≤ N) { await ~b[j] ;
j := j+1 } ;
l9: if (y ̸= self) { l10: await y = 0 ;
goto start } } ;
cs: skip ; \∗ The critical section.
l11: y := 0 ;
l12: b[self] := FALSE } } }
